/**
 * Generated-file templates for the Node SDK installer (ADR-069 §1).
 *
 * Three flavors so the inserted file matches the host package's module
 * system: CJS for `require`-based packages, ESM for `import`-based, TS for
 * TypeScript entries. Env vars are inlined as `process.env.X ||=` defaults
 * rather than loaded from `.env.neat` at runtime — `__dirname` /
 * `import.meta.url` resolve unpredictably once a bundler rewrites the
 * generated file (Brief-smoke evidence, issue #369), so we let the OTel SDK
 * read its config from the same `process.env` either way. Platform env
 * (Vercel / Railway / Fly / etc.) stays authoritative at deploy time;
 * `||=` keeps the local default for laptop dev only.
 */

// Header comment that ships at the top of every generated otel-init. Stable
// across flavors so a grep for the header line finds every generated file in
// a target codebase. Used by the idempotency check too (ADR-069 §6).
export const OTEL_INIT_HEADER = '// Generated by `neat init --apply` (ADR-069). OpenTelemetry auto-instrumentation hook.'

// Version stamp carried by every NEAT-owned generated file (the otel-init and
// the call-site processor). On a re-run the installer reads the stamp off the
// file on disk and regenerates when it's older than this number, so existing
// installs migrate onto the current template without the user re-running by
// hand (ADR-087 §2). This is the single migration mechanism every future
// template change rides — bump it whenever the otel-init or the processor body
// changes shape.
//
// 1 — v0.4.7: the otel-init wires the call-site SpanProcessor and the SDK now
//     constructs its own OTLP exporter so the enriching processor sits in the
//     same pipeline.
export const NEAT_TEMPLATE_VERSION = 1

// The stamp rides as a comment line so it survives unchanged through the
// placeholder substitution in the render functions below. `parseTemplateVersion`
// reads it back; a file with no stamp (pre-v0.4.7 install) reads as null and
// the installer treats that as "older than current" and migrates it.
const templateStamp = (version: number): string => `// neat:template-version=${version}`

export function parseTemplateVersion(contents: string): number | null {
  const match = contents.match(/neat:template-version=(\d+)/)
  return match ? Number.parseInt(match[1]!, 10) : null
}

// __SERVICE_NAME__ → the ServiceNode id (the package's `pkg.name`, or the
// directory basename for nameless packages); __PROJECT__ → the registered
// project basename; __INSTRUMENTATION_BLOCK__ → a (possibly empty) sequence
// of `instrumentations.push(...)` lines for non-bundled instrumentations
// (Prisma for v0.4.5; more libraries via the v0.5.0 registry). All three are
// substituted at apply time via renderNodeOtelInit().
//
// v0.4.5 — explicit `NodeSDK` construction replaces the
// `auto-instrumentations-node/register` shorthand so non-bundled libraries
// (Prisma's Rust query engine bypasses node-pg; Drizzle, BetterAuth, etc.
// have their own packages) can compose into the same `instrumentations`
// array without templating a different file shape per library.
// v0.4.7 (ADR-087) — the SDK now constructs its own OTLP exporter and span
// processor list rather than letting NodeSDK build the default pipeline from
// the environment. That's the only way to slot the call-site processor into
// the live pipeline: NodeSDK's `spanProcessors` option replaces the env-derived
// exporter, so we re-supply it (the wire protocol is unchanged — http/protobuf
// against the same `OTEL_EXPORTER_OTLP_TRACES_ENDPOINT` the env path read).
// `tracing.BatchSpanProcessor` rides on the sdk-node re-export so only the
// exporter joins the dependency list.
export const OTEL_INIT_CJS = `${OTEL_INIT_HEADER}
${templateStamp(NEAT_TEMPLATE_VERSION)}
process.env.OTEL_SERVICE_NAME ||= '__SERVICE_NAME__'
process.env.OTEL_EXPORTER_OTLP_TRACES_ENDPOINT ||= 'http://localhost:4318/projects/__PROJECT__/v1/traces'

const { NodeSDK, tracing } = require('@opentelemetry/sdk-node')
const { getNodeAutoInstrumentations } = require('@opentelemetry/auto-instrumentations-node')
const { OTLPTraceExporter } = require('@opentelemetry/exporter-trace-otlp-proto')
const { NeatCallSiteProcessor } = require('./neat-callsite-processor.cjs')

const instrumentations = [getNodeAutoInstrumentations()]
__INSTRUMENTATION_BLOCK__
new NodeSDK({
  instrumentations,
  spanProcessors: [
    new NeatCallSiteProcessor(),
    new tracing.BatchSpanProcessor(new OTLPTraceExporter()),
  ],
}).start()
`

export const OTEL_INIT_ESM = `${OTEL_INIT_HEADER}
${templateStamp(NEAT_TEMPLATE_VERSION)}
process.env.OTEL_SERVICE_NAME ||= '__SERVICE_NAME__'
process.env.OTEL_EXPORTER_OTLP_TRACES_ENDPOINT ||= 'http://localhost:4318/projects/__PROJECT__/v1/traces'

import { NodeSDK, tracing } from '@opentelemetry/sdk-node'
import { getNodeAutoInstrumentations } from '@opentelemetry/auto-instrumentations-node'
import { OTLPTraceExporter } from '@opentelemetry/exporter-trace-otlp-proto'
import { NeatCallSiteProcessor } from './neat-callsite-processor.mjs'

const instrumentations = [getNodeAutoInstrumentations()]
__INSTRUMENTATION_BLOCK__
new NodeSDK({
  instrumentations,
  spanProcessors: [
    new NeatCallSiteProcessor(),
    new tracing.BatchSpanProcessor(new OTLPTraceExporter()),
  ],
}).start()
`

export const OTEL_INIT_TS = `${OTEL_INIT_HEADER}
${templateStamp(NEAT_TEMPLATE_VERSION)}
process.env.OTEL_SERVICE_NAME ||= '__SERVICE_NAME__'
process.env.OTEL_EXPORTER_OTLP_TRACES_ENDPOINT ||= 'http://localhost:4318/projects/__PROJECT__/v1/traces'

import { NodeSDK, tracing } from '@opentelemetry/sdk-node'
import { getNodeAutoInstrumentations } from '@opentelemetry/auto-instrumentations-node'
import { OTLPTraceExporter } from '@opentelemetry/exporter-trace-otlp-proto'
import { NeatCallSiteProcessor } from './neat-callsite-processor'

const instrumentations = [getNodeAutoInstrumentations()]
__INSTRUMENTATION_BLOCK__
new NodeSDK({
  instrumentations,
  spanProcessors: [
    new NeatCallSiteProcessor(),
    new tracing.BatchSpanProcessor(new OTLPTraceExporter()),
  ],
}).start()
`

// Substitute __SERVICE_NAME__, __PROJECT__, and __INSTRUMENTATION_BLOCK__
// at apply time. The third arg is a list of registration snippets — one per
// non-bundled instrumentation the installer detected (e.g. Prisma). An empty
// list collapses the placeholder to nothing so the generated file stays
// readable on the common "auto-instrumentations covers everything" path.
export function renderNodeOtelInit(
  template: string,
  serviceName: string,
  projectName: string,
  registrations: readonly string[] = [],
): string {
  const block = registrations.length === 0 ? '' : `\n${registrations.join('\n')}\n`
  return template
    .replace(/__SERVICE_NAME__/g, serviceName)
    .replace(/__PROJECT__/g, projectName)
    .replace(/__INSTRUMENTATION_BLOCK__\n?/g, block)
}

// .env.neat shape (ADR-069 §4, amended v0.4.1 — refs #339, v0.4.4 — refs
// #367 + #369). Two keys: OTEL_SERVICE_NAME (the ServiceNode id — the
// package's own name, scope-preserved, so spans land on per-service nodes
// inside the project's graph) and OTEL_EXPORTER_OTLP_TRACES_ENDPOINT (the
// project-scoped URL the daemon mounts at /projects/<project>/v1/traces).
// Both env vars are advisory only — the generated `otel-init` inlines them
// via `process.env.X ||=` so bundlers can't lose them; the file is kept so
// operators can grep for service.name → project mapping in one place.
export function renderEnvNeat(serviceName: string, projectName: string): string {
  return [
    '# Generated by `neat init --apply` (ADR-069).',
    `OTEL_SERVICE_NAME=${serviceName}`,
    `OTEL_EXPORTER_OTLP_TRACES_ENDPOINT=http://localhost:4318/projects/${projectName}/v1/traces`,
    '',
  ].join('\n')
}

// ── Call-site SpanProcessor (ADR-087 §2). ───────────────────────────────
//
// The load-bearing piece of file-awareness at the OBSERVED source. The plain
// `auto-instrumentations-node` set attributes a span to `service.name` and
// nothing finer. This processor runs synchronously in `onStart`, in the same
// call stack that created the span, so a stack capture there still holds the
// user's call site. On CLIENT/PRODUCER spans (outbound work — an HTTP call, a
// `pg`/`mysql2`/`ioredis` query) it walks the captured stack, drops the
// `node_modules` and `@opentelemetry/*` frames, and stamps the first remaining
// user frame onto the span as `code.filepath` / `code.lineno` / `code.function`.
// Ingest reads those into file-grained `evidence` on the OBSERVED edge.
//
// SERVER spans get nothing: a server span's call site is inside the framework,
// not the user's code, so there is no honest call site to attach (ADR-087 §3 —
// evidence is never fabricated). Spans created off the caller's synchronous
// path (engine-proxied libraries, queued work) also fall through to no frame
// rather than a wrong one.
//
// The module is emitted as a sibling of the generated otel-init and imported
// by it, so the processor body version-stamps and migrates on the same
// mechanism as the otel-init.
export const NEAT_CALLSITE_PROCESSOR_HEADER =
  '// Generated by `neat init --apply` (ADR-087). Call-site SpanProcessor — attaches code.* file origin to CLIENT/PRODUCER spans.'

export const NEAT_CALLSITE_PROCESSOR_CJS = `${NEAT_CALLSITE_PROCESSOR_HEADER}
${templateStamp(NEAT_TEMPLATE_VERSION)}
const { SpanKind } = require('@opentelemetry/api')

const NEAT_SKIP = /[\\\\/]node_modules[\\\\/]|[\\\\/]@opentelemetry[\\\\/]/

class NeatCallSiteProcessor {
  forceFlush() { return Promise.resolve() }
  onEnd() {}
  shutdown() { return Promise.resolve() }
  onStart(span) {
    const kind = span.kind
    if (kind !== SpanKind.CLIENT && kind !== SpanKind.PRODUCER) return
    // Capture structured V8 call frames rather than the formatted stack string:
    // we scan for the first user frame and stop, so we never pay to render the
    // whole trace. prepareStackTrace is swapped only for this synchronous
    // capture and restored before anything else can observe it.
    const holder = {}
    const prevPrepare = Error.prepareStackTrace
    const prevLimit = Error.stackTraceLimit
    Error.stackTraceLimit = 30
    Error.prepareStackTrace = (_e, frames) => frames
    Error.captureStackTrace(holder, this.onStart)
    const frames = holder.stack
    Error.prepareStackTrace = prevPrepare
    Error.stackTraceLimit = prevLimit
    if (!Array.isArray(frames)) return
    for (const frame of frames) {
      const file = frame.getFileName()
      if (!file || file.startsWith('node:') || NEAT_SKIP.test(file)) continue
      span.setAttribute('code.filepath', file)
      const lineno = frame.getLineNumber()
      if (lineno != null) span.setAttribute('code.lineno', lineno)
      const fn = frame.getFunctionName()
      if (fn) span.setAttribute('code.function', fn)
      return
    }
  }
}

module.exports = { NeatCallSiteProcessor }
`

